public enum ApplicationCommand: Equatable, Hashable {

    case subscribeToFeed(feedUrl: String
    )
    case ensurePodcast(feedUrl: String
    )
    case refreshPodcast(podcastId: PodcastId
    )
    case hydratePodcastMetadata(podcastId: PodcastId
    )
    case upsertSyntheticPodcast(podcast: SyntheticPodcastInput
    )
    case upsertExternalEpisode(episode: ExternalEpisodeInput
    )
    case unsubscribe(podcastId: PodcastId
    )
    case setSubscriptionNotifications(podcastId: PodcastId, enabled: Bool
    )
    case setSubscriptionAutoDownload(podcastId: PodcastId, policy: AutoDownloadPolicy
    )
    case setEpisodeStarred(episodeId: EpisodeId, starred: Bool
    )
    case resetListeningData
    case requestPlayback(episodeId: EpisodeId
    )
    case playback(command: PlaybackCommand
    )
    case recallQuery(query: RecallQuery
    )
    case rebuildTranscriptEvidence(input: TranscriptEvidenceInput, policy: EvidenceChunkPolicy
    )
    case createNote(text: String, kind: NoteKind, author: NoteAuthor, target: NoteTarget?
    )
    case updateNote(noteId: NoteId, expectedNoteRevision: NoteRevision, text: String, kind: NoteKind, target: NoteTarget?
    )
    case setNoteDeleted(noteId: NoteId, expectedNoteRevision: NoteRevision, deleted: Bool
    )
    case clearNotes(expectedCollectionRevision: StateRevision
    )
    case cancelOperation(cancellationId: CancellationId
    )
    case unsupported(wireCode: UInt32
    )





}

#if compiler(>=6)
extension ApplicationCommand: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeApplicationCommand: FfiConverterRustBuffer {
    typealias SwiftType = ApplicationCommand

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ApplicationCommand {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        case 1: return .subscribeToFeed(feedUrl: try FfiConverterString.read(from: &buf)
        )

        case 2: return .ensurePodcast(feedUrl: try FfiConverterString.read(from: &buf)
        )

        case 3: return .refreshPodcast(podcastId: try FfiConverterTypePodcastId.read(from: &buf)
        )

        case 4: return .hydratePodcastMetadata(podcastId: try FfiConverterTypePodcastId.read(from: &buf)
        )

        case 5: return .upsertSyntheticPodcast(podcast: try FfiConverterTypeSyntheticPodcastInput.read(from: &buf)
        )

        case 6: return .upsertExternalEpisode(episode: try FfiConverterTypeExternalEpisodeInput.read(from: &buf)
        )

        case 7: return .unsubscribe(podcastId: try FfiConverterTypePodcastId.read(from: &buf)
        )

        case 8: return .setSubscriptionNotifications(podcastId: try FfiConverterTypePodcastId.read(from: &buf), enabled: try FfiConverterBool.read(from: &buf)
        )

        case 9: return .setSubscriptionAutoDownload(podcastId: try FfiConverterTypePodcastId.read(from: &buf), policy: try FfiConverterTypeAutoDownloadPolicy.read(from: &buf)
        )

        case 10: return .setEpisodeStarred(episodeId: try FfiConverterTypeEpisodeId.read(from: &buf), starred: try FfiConverterBool.read(from: &buf)
        )

        case 11: return .resetListeningData

        case 12: return .requestPlayback(episodeId: try FfiConverterTypeEpisodeId.read(from: &buf)
        )

        case 13: return .playback(command: try FfiConverterTypePlaybackCommand.read(from: &buf)
        )

        case 14: return .recallQuery(query: try FfiConverterTypeRecallQuery.read(from: &buf)
        )

        case 15: return .rebuildTranscriptEvidence(input: try FfiConverterTypeTranscriptEvidenceInput.read(from: &buf), policy: try FfiConverterTypeEvidenceChunkPolicy.read(from: &buf)
        )

        case 16: return .createNote(text: try FfiConverterString.read(from: &buf), kind: try FfiConverterTypeNoteKind.read(from: &buf), author: try FfiConverterTypeNoteAuthor.read(from: &buf), target: try FfiConverterOptionTypeNoteTarget.read(from: &buf)
        )

        case 17: return .updateNote(noteId: try FfiConverterTypeNoteId.read(from: &buf), expectedNoteRevision: try FfiConverterTypeNoteRevision.read(from: &buf), text: try FfiConverterString.read(from: &buf), kind: try FfiConverterTypeNoteKind.read(from: &buf), target: try FfiConverterOptionTypeNoteTarget.read(from: &buf)
        )

        case 18: return .setNoteDeleted(noteId: try FfiConverterTypeNoteId.read(from: &buf), expectedNoteRevision: try FfiConverterTypeNoteRevision.read(from: &buf), deleted: try FfiConverterBool.read(from: &buf)
        )

        case 19: return .clearNotes(expectedCollectionRevision: try FfiConverterTypeStateRevision.read(from: &buf)
        )

        case 20: return .cancelOperation(cancellationId: try FfiConverterTypeCancellationId.read(from: &buf)
        )

        case 21: return .unsupported(wireCode: try FfiConverterUInt32.read(from: &buf)
        )

        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: ApplicationCommand, into buf: inout [UInt8]) {
        switch value {


        case let .subscribeToFeed(feedUrl):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(feedUrl, into: &buf)


        case let .ensurePodcast(feedUrl):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(feedUrl, into: &buf)


        case let .refreshPodcast(podcastId):
            writeInt(&buf, Int32(3))
            FfiConverterTypePodcastId.write(podcastId, into: &buf)


        case let .hydratePodcastMetadata(podcastId):
            writeInt(&buf, Int32(4))
            FfiConverterTypePodcastId.write(podcastId, into: &buf)


        case let .upsertSyntheticPodcast(podcast):
            writeInt(&buf, Int32(5))
            FfiConverterTypeSyntheticPodcastInput.write(podcast, into: &buf)


        case let .upsertExternalEpisode(episode):
            writeInt(&buf, Int32(6))
            FfiConverterTypeExternalEpisodeInput.write(episode, into: &buf)


        case let .unsubscribe(podcastId):
            writeInt(&buf, Int32(7))
            FfiConverterTypePodcastId.write(podcastId, into: &buf)


        case let .setSubscriptionNotifications(podcastId,enabled):
            writeInt(&buf, Int32(8))
            FfiConverterTypePodcastId.write(podcastId, into: &buf)
            FfiConverterBool.write(enabled, into: &buf)


        case let .setSubscriptionAutoDownload(podcastId,policy):
